* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

:root {
  /* Colors */
  --clr-primary-purple: hsl(246, 80%, 60%);
  --clr-work: hsl(15, 100%, 70%);
  --clr-play: hsl(195, 74%, 62%);
  --clr-study: hsl(348, 100%, 68%);
  --clr-exercise: hsl(145, 58%, 55%);
  --clr-social: hsl(264, 64%, 52%);
  --clr-self-care: hsl(43, 84%, 65%);

  --clr-neutral-very-dark-blue: hsl(226, 43%, 10%);
  --clr-neutral-dark-blue: hsl(235, 46%, 20%);
  --clr-neutral-desaturated-blue: hsl(235, 45%, 61%);
  --clr-neutral-pale-blue: hsl(236, 100%, 87%);
  --clr-hover-dark-blue: hsl(235, 45%, 33%);

  /* Typography */
  --font-family: 'Rubik', sans-serif;
  --fw-light: 300;
  --fw-regular: 400;
  --fw-medium: 500;
}

body {
  font-family: var(--font-family);
  background-color: var(--clr-neutral-very-dark-blue);
  color: white;
  min-height: 100vh;
  display: grid;
  place-content: center;
  font-size: 18px;
  margin: 0;
  padding: 2rem 1.5rem;
}

/* Typography elements */
h1, h2, p {
  line-height: 1.2;
}

/* Button Resets */
button {
  background: none;
  border: none;
  cursor: pointer;
  font-family: inherit;
  color: inherit;
}

