{"content":"const timeframeBtns = document.querySelectorAll('.timeframe-btn');
const activitiesContainer = document.getElementById('activities-container');
const template = document.getElementById('activity-card-template');

let activityData = [];

// Fetch data
async function fetchData() {
  try {
    const response = await fetch('./data.json');
    if (!response.ok) {
      throw new Error(`HTTP error! status: ${response.status}`);
    }
    activityData = await response.json();
    renderActivities('weekly'); // Default timeframe
  } catch (error) {
    console.error('Error loading data:', error);
  }
}

// Format the class name for the activity card CSS
function getClassName(title) {
  return title.toLowerCase().replace(/\s+/g, '-');
}

function getTimeframeText(timeframe) {
  switch (timeframe) {
    case 'daily':
      return 'Yesterday';
    case 'weekly':
      return 'Last Week';
    case 'monthly':
      return 'Last Month';
    default:
      return 'Previous';
  }
}

function renderActivities(timeframe) {
  activitiesContainer.innerHTML = ''; // Clear container

  activityData.forEach(activity => {
    const clone = template.content.cloneNode(true);
    const card = clone.querySelector('.activity-card');

    // Add specific class for background color and icon
    const className = getClassName(activity.title);
    card.classList.add(className);

    // Set title
    clone.querySelector('.activity-title').textContent = activity.title;

    // Get time data
    const current = activity.timeframes[timeframe].current;
    const previous = activity.timeframes[timeframe].previous;

    // Set times
    clone.querySelector('.current-time').textContent = `${current}hr${current !== 1 ? 's' : ''}`;

    const previousText = getTimeframeText(timeframe);
    clone.querySelector('.previous-time').textContent = `${previousText} - ${previous}hr${previous !== 1 ? 's' : ''}`;

    activitiesContainer.appendChild(clone);
  });
}

// Event listeners for timeframe buttons
timeframeBtns.forEach(btn => {
  btn.addEventListener('click', () => {
    // Update active state
    timeframeBtns.forEach(b => b.classList.remove('active'));
    btn.classList.add('active');

    // Render with new timeframe
    const timeframe = btn.dataset.timeframe;
    renderActivities(timeframe);
  });
});

// Initialize
fetchData();
